# Project name becomes an AWS secret id, Supabase display name, Amplify app name,
# and a DNS prefix downstream. Restrict it to letters, digits, and hyphens so a bad
# name fails here instead of silently breaking remote resources.
_PROJECT_NAME_PATTERN = re.compile(r"^[A-Za-z0-9-]+$")


def _normalize_start_inputs(
    *,
    github_url: str,
    user_email: str,
    project_name: str,
    target_repo_url: str,
) -> tuple[str, str, str, str] | StartFailure:
    gh = github_url.strip()
    email = user_email.strip()
    project = project_name.strip()
    if not gh:
        return _validation_failure("githubUrl is required")
    if not email:
        return _validation_failure("userEmail is required")
    if not project:
        return _validation_failure("projectName is required")
    if not _PROJECT_NAME_PATTERN.fullmatch(project):
        return _validation_failure(
            "projectName must contain only letters, digits, and hyphens "
            "(no spaces or special characters)"
        )
    target = target_repo_url.strip() or gh
    return gh, email, project, target

